from django.utils.safestring import mark_safe

class MediaOrderConflictWarning(UserWarning):
    pass

class Media:
    def __init__(self, media=None, **kwargs):
        self._css = kwargs.pop('css', {})
        self._js = kwargs.pop('js', [])
        if media is not None:
            for key in ('css', 'js'):
                getattr(self, '_add_%s' % key)(getattr(media, key, {}))

    def _add_css(self, css):
        for medium, paths in css.items():
            if medium in self._css:
                self._css[medium].extend(path for path in paths if path not in self._css[medium])
            else:
                self._css[medium] = list(paths)

    def _add_js(self, js):
        existing_js_set = set(self._js)
        self._js.extend(x for x in js if x not in existing_js_set)

    def render(self):
