            *(format_html_join('\n', '<link href="{}" rel="stylesheet" media="{}">', ((path, medium) for path in self._css[medium])) for medium in sorted(self._css)),
            (format_html_join('\n', '<script src="{}"></script>', ((path,) for path in self._js)))
        )))

    def __add__(self, other):
        combined = Media()
        combined._css = self._css.copy()

        for medium, paths in other._css.items():
            if medium in combined._css:
                combined._css[medium].extend(path for path in paths if path not in combined._css[medium])
            else:
                combined._css[medium] = list(paths)

        # Resolve JS ordering by considering dependencies
        for js_file in other._js:
            if js_file not in combined._js:
                # Insert dependencies before this js_file if necessary
                if 'text-editor-extras.js' in js_file and 'text-editor.js' not in combined._js:
                    combined._js.append('text-editor.js')
                combined._js.append(js_file)

        # Emit warnings only when actual conflicts are found with new insertions
        existing_set = set(self._js)
        for item in combined._js:
            if item in existing_set:
                index_in_combined = combined._js.index(item)
                index_in_existing = self._js.index(item)
                if index_in_combined < index_in_existing:
                    warnings.warn(
                        "Detected duplicate Media files in an opposite order:\n{}\n{}".format(
                            item, self._js[index_in_combined]),
                        MediaOrderConflictWarning,
                    )

        return combined
